class Fan:    SLOW = 1    MIDIUM = 2    FAST = 3    def __init__(self, speed = MIDIUM, radius = 5.0, color = "BLUE", on = False ):        self.speed = speed        self.radius = radius        self.color = color        self.on = on    def get_speed(self):        return self.speed    def set_radius(self):        return self.radius    def set_color(self):        return self.color    def is_on(self):        return self.on